#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 1e5+5;
struct line{int x,y;LL w;}ln[N];
LL n,m,dis[N],p[65],Ans;
bool vis[N];
vector<pLL> g[N];
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void DFS(int u,int fa){
    vis[u]=1;
    for(auto [v,w]:g[u])
        if(v^fa&&!vis[v])dis[v]=dis[u]^w,DFS(v,u);
    return;
}
void Insert(LL x){
    for(int i=62;i>=0;i--)
        if((x>>i)&1){
            if(!p[i]){p[i]=x;break;}
            else x^=p[i];
        }
    return;
}
int main(){
    n=read(),m=read();
    for(int i=1;i<=m;i++){
        int x=read(),y=read();
        LL w=read();ln[i]={x,y,w};
        g[x].pb({y,w}),g[y].pb({x,w});
    }DFS(1,0);
    for(int i=1;i<=m;i++){
        auto [x,y,w]=ln[i];
        LL ds=dis[x]^dis[y]^w;
        if(ds!=0)Insert(ds);
    }Ans=dis[n];
    for(int i=62;i>=0;i--)
        if((Ans^p[i])>Ans)Ans^=p[i];
    cout<<Ans<<"\n";
    return 0;
}
